OUTDIR = os.path.expanduser(os.environ.get("SHEETS_OUTDIR", "."))

# ---- design tokens (synced to the floorcraft board) ----
BLUE="#1A6BAA"; INK="#222222"; RED="#C0392B"; GRID="#e7e3da"; LODC="#8a8478"; FLOORC="#f7f5f0"
