    {"id":"Waltz_PreBronze_Routine_1",    "layout":"WALTZ1_LAYOUT",         "dance":"Waltz",       "level":"Pre-Bronze","routine":1,"version":"v4","subtitle":""},
    {"id":"Waltz_Intermediate_Routine_1",    "layout":"WALTZ2_LAYOUT",         "dance":"Waltz",       "level":"Intermediate","routine":1,"version":"v1","subtitle":""},
    {"id":"Waltz_Newcomer_Routine_1",     "layout":"WALTZ_NEWCOMER_LAYOUT", "dance":"Waltz",       "level":"Newcomer",  "routine":1,"version":"v1","subtitle":""},
    {"id":"Tango_Intermediate_Routine_1",    "layout":"TANGO_LAYOUT",          "dance":"Tango",       "level":"Intermediate","routine":1,"version":"v1","subtitle":""},
    {"id":"Tango_Newcomer_Routine_1",     "layout":"TANGO_NEWCOMER_LAYOUT", "dance":"Tango",       "level":"Newcomer",  "routine":1,"version":"v1","subtitle":""},
    {"id":"Foxtrot_Bronze_Routine_1",     "layout":"FOXTROT_LAYOUT",        "dance":"Foxtrot",    "level":"Bronze",    "routine":1,"version":"v1","subtitle":"Feather · Three Step · Natural Turn · Heel Pull"},
    {"id":"Quickstep_PreBronze_Routine_1","layout":"QUICKSTEP_LAYOUT",      "dance":"Quickstep",   "level":"Pre-Bronze","routine":1,"version":"v1","subtitle":""},
    {"id":"Foxtrot_Intermediate_Routine_1","layout":"FOXTROT_INTERMEDIATE_LAYOUT","dance":"Foxtrot","level":"Intermediate","routine":1,"version":"v1","subtitle":""},
