# board screen (x right, y down)  ->  matplotlib plot (y up), identical look
def MP(x, y):  return (x, FD - y)
def pa(a):     return -a                       # board heading -> plot heading
def centre(g): return ((g["L"]["x"]+g["F"]["x"])/2.0, (g["L"]["y"]+g["F"]["y"])/2.0)

def draw_dancer(ax, dn, color, ghost):
    X, Y = MP(dn["x"], dn["y"]); a = dn["a"]; ta = dn.get("tick", a); al = GHOST_A if ghost else 1.0
    # body: short axis (0.6) along facing, long axis (1.62) across the shoulders
    ax.add_patch(Ellipse((X, Y), width=0.6, height=1.62, angle=math.degrees(pa(a)),
                         facecolor=color, edgecolor="white", lw=1.0, alpha=al, zorder=4))
    ax.add_patch(Circle((X, Y), 0.2, facecolor=color, edgecolor="white", lw=1.0, alpha=al, zorder=5))
    fa = pa(ta)
    ax.annotate("", xy=(X+0.80*math.cos(fa), Y+0.80*math.sin(fa)),
                xytext=(X+0.24*math.cos(fa), Y+0.24*math.sin(fa)),
                arrowprops=dict(arrowstyle="-|>", color=color, lw=1.6, alpha=al), zorder=5)

def draw_couple(ax, L, Fl, ghost):
    draw_dancer(ax, L, INK, ghost)
    draw_dancer(ax, Fl, RED, ghost)

def label_lines(text, br):
    w = text.split(" ")
    if br and 0 < br < len(w):
        return [" ".join(w[:br]), " ".join(w[br:])]
    return [text]

def draw_lod_ring(ax):
    arr = dict(arrowstyle="-|>", color=LODC, lw=1.4)
    # counter-clockwise: bottom->right, right->up, top->left, left->down
    ax.annotate("", xy=(17.5, -0.75), xytext=(12.5, -0.75), arrowprops=arr)          # bottom: ->
    ax.text(11.6, -0.75, "LOD", ha="right", va="center", fontsize=8, color=LODC, family=HEAD)
    ax.annotate("", xy=(FW+0.75, 12.5), xytext=(FW+0.75, 7.5), arrowprops=arr)        # right: up
    ax.text(FW+0.75, 6.6, "LOD", ha="center", va="top", fontsize=8, color=LODC, family=HEAD)
    ax.annotate("", xy=(12.5, FD+0.75), xytext=(17.5, FD+0.75), arrowprops=arr)       # top: <-
    ax.text(18.4, FD+0.75, "LOD", ha="left", va="center", fontsize=8, color=LODC, family=HEAD)
    ax.annotate("", xy=(-0.75, 7.5), xytext=(-0.75, 12.5), arrowprops=arr)            # left: down
    ax.text(-0.75, 13.4, "LOD", ha="center", va="bottom", fontsize=8, color=LODC, family=HEAD)

def draw_rhythm(ax, rhythm):
    # plain text inside the floor, upper-right (matches the board placement)
    x0, y0 = 18.0, 2.65
    X, Y = MP(x0, y0)
    ax.text(X, Y, "Rhythm", ha="left", va="center", fontsize=9.5,
            fontweight="bold", color=BLUE, family=HEAD, zorder=10)
    for i, r in enumerate(rhythm):
        Xi, Yi = MP(x0, y0 + 1.05 + i*0.95)
        ax.text(Xi, Yi, r["fig"], ha="left", va="center", fontsize=8.5, color=INK, family=HEAD, zorder=10)
        ax.text(Xi + 6.1, Yi, r["pattern"], ha="left", va="center", fontsize=9, color=BLUE,
                family=MONO, zorder=10)


_RAYLAB = {0: "LOD", 45: "DW", 90: "Wall", 135: "BDC", 180: "against LOD", 225: None, 270: "Centre", 315: "DC"}
def _emph_from_ghosts(lay):
    emph = set()
    for g in lay.get("ghosts", []):
        a = g.get("L", {}).get("a", 0.0)
        deg = int(round((math.degrees(a) % 360) / 45.0)) * 45 % 360
        lab = _RAYLAB.get(deg)
        if lab:
            emph.add(lab)
    return emph

def draw_compass(ax, cx, cy, r, emph):
    RAYS = [(0,"LOD"),(45,"DW"),(90,"Wall"),(135,"BDC"),
            (180,"against LOD"),(225,None),(270,"Centre"),(315,"DC")]
    Cx, Cy = MP(cx, cy)
    ax.add_patch(Circle((Cx, Cy), r, facecolor="white", edgecolor=GRID, lw=0.8, alpha=0.55, zorder=4))
    ax.add_patch(Circle((Cx, Cy), 0.11, facecolor=INK, edgecolor="none", zorder=7))
    for deg, lab in RAYS:
        a = math.radians(deg)
        tx, ty = MP(cx + r*math.cos(a), cy + r*math.sin(a))
        is_e = (lab in emph) if lab else False
        col  = INK if is_e else LODC
        lw   = 2.2 if is_e else 0.9
        ax.annotate("", xy=(tx,ty), xytext=(Cx,Cy),
                    arrowprops=dict(arrowstyle=("-|>" if is_e else "-"),
                                    color=col, lw=lw, shrinkA=0, shrinkB=0), zorder=6)
        if lab:
            if deg == 180:                      # 'against' over 'LOD', left-aligned, left of the ray tip
                tx, ty = MP(cx + r*math.cos(a), cy + r*math.sin(a))
                ax.text(tx, ty, "against\nLOD", ha="right", ma="left", va="center",
                        fontsize=(7.6 if is_e else 6.8),
                        fontweight=("bold" if is_e else "normal"),
                        color=col, family=HEAD, zorder=7)
            else:
                lx, ly = MP(cx + (r+0.6)*math.cos(a), cy + (r+0.6)*math.sin(a))
                ax.text(lx, ly, lab, ha="center", va="center",
                        fontsize=(7.6 if is_e else 6.8),
                        fontweight=("bold" if is_e else "normal"),
                        color=col, family=HEAD, zorder=7)

def draw_shadow_legend(ax):
    # leader/follower shadow key; sits above the rhythm block (rhythm header is at board y=2.4)
    bx = 18.0
    ax.text(*MP(bx, 0.75), "Dancers", ha="left", va="center", fontsize=9.5,
            fontweight="bold", color=BLUE, family=HEAD, zorder=10)
    for i, (lab, col) in enumerate([("Leader", INK), ("Follower", RED)]):
        gx = bx + 0.4 + i*3.5
        GX, GY = MP(gx, 1.6)
        ax.add_patch(Ellipse((GX, GY), width=0.5, height=1.05, angle=0,
                             facecolor=col, edgecolor="white", lw=0.9, alpha=GHOST_A, zorder=10))
        ax.add_patch(Circle((GX, GY), 0.15, facecolor=col, edgecolor="white", lw=0.9, alpha=GHOST_A, zorder=11))
        ax.text(*MP(gx + 0.5, 1.6), lab, ha="left", va="center", fontsize=8.5,
                color=INK, family=HEAD, zorder=10)

def render(sheet):
    lay = LAYOUTS[sheet["layout"]]
    fig = plt.figure(figsize=(11.69, 8.27))    # A4 landscape
    fig.text(0.5, 0.965, "Dance PRAKTIKA", ha="center", va="top", fontsize=18,
             fontweight="bold", color=BLUE, family=HEAD)
    fig.text(0.5, 0.928, "%s \u2014 %s \u2014 Routine %d" % (sheet["dance"], sheet["level"], sheet["routine"]),
             ha="center", va="top", fontsize=13, fontweight="bold", color=INK, family=HEAD)
    if sheet.get("subtitle"):
        fig.text(0.5, 0.902, sheet["subtitle"], ha="center", va="top", fontsize=8.5, color=LODC, family=HEAD)

    ax = fig.add_axes([0.04, 0.04, 0.92, 0.83])
    ax.set_xlim(-2.0, FW+2.0); ax.set_ylim(-2.0, FD+2.0)
    ax.set_aspect("equal"); ax.axis("off")

    # floor + 1 m grid + border
    ax.add_patch(Rectangle((0,0), FW, FD, facecolor=FLOORC, edgecolor="none", zorder=0))
    ax.add_patch(Rectangle((0,0), FW, FD, facecolor="none", edgecolor=INK, lw=2.0, zorder=3))
    draw_lod_ring(ax)

    # path (black, 60%)
    pts = [MP(p["x"], p["y"]) for p in lay["path"]]
    ax.plot([q[0] for q in pts], [q[1] for q in pts], color=INK, lw=2.2, alpha=0.6,
            solid_capstyle="round", solid_joinstyle="round", zorder=2)

    # ghosts (ghosted + numbered badge) then the live/End couple (solid)
    for g in lay["ghosts"]:
        draw_couple(ax, g["L"], g["F"], ghost=True)
    for g in lay["ghosts"]:
        cx, cy = centre(g); X, Y = MP(cx, cy)
        ax.add_patch(Circle((X, Y), 0.34, facecolor="white", edgecolor=BLUE, lw=1.3, zorder=6))
        ax.text(X, Y, str(g["n"]), ha="center", va="center", fontsize=8.5, fontweight="bold",
                color=BLUE, family=HEAD, zorder=7)
    draw_couple(ax, lay["leader"], lay["follower"], ghost=False)

    # figure-name labels
    for l in lay["figLabels"]:
        X, Y = MP(l["x"], l["y"])
        ax.text(X, Y, "\n".join(label_lines(l["text"], l.get("br", 0))),
                ha="center", va="center", fontsize=8.5, color=INK, fontweight="bold",
                family=HEAD, rotation=-l.get("rot", 0), zorder=8,
                bbox=dict(boxstyle="round,pad=0.16", fc="white", ec="none", alpha=0.78))

    draw_shadow_legend(ax)
    if lay.get("rhythm"):
        draw_rhythm(ax, lay["rhythm"])

    draw_compass(ax, 4.2, 4.3, 2.2, _emph_from_ghosts(lay))

    fig.text(0.96, 0.025, "%s \u00b7 %s" % (sheet["id"], sheet.get("version","v1")),
             ha="right", fontsize=6.5, color=LODC, family=HEAD)

    out = os.path.join(OUTDIR, "%s_%s.pdf" % (sheet["id"], sheet.get("version","v1")))
    with PdfPages(out) as pdf: pdf.savefig(fig)
    plt.close(fig)
    return out

def main():
    os.makedirs(OUTDIR, exist_ok=True)
    wanted = set(sys.argv[1:])
    for s in SHEETS:
        if wanted and s["id"] not in wanted: continue
        print("wrote", render(s))

if __name__ == "__main__":
    main()
